import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import API from "../services/api";
import Navbar from "../components/Navbar";

function Admin() {
  const navigate = useNavigate();

  const [counts, setCounts] = useState({
    totalAnimals: 0,
    totalEnclosures: 0,
    totalStaff: 0,
    totalFeedingSchedules: 0,
    totalMedicalRecords: 0,
    totalUsers: 0,
  });

  useEffect(() => {
    fetchCounts();
  }, []);

  const fetchCounts = async () => {
    try {
      const res = await API.get("/dashboard/counts");
      setCounts(res.data);
    } catch (error) {
      console.error("Error loading dashboard counts:", error);
    }
  };

  return (
    <div style={styles.page}>
      <Navbar />

      <div style={styles.container}>
        <div style={styles.headerCard}>
          <h1 style={styles.title}>Admin Dashboard</h1>
          <p style={styles.subtitle}>
            Manage the entire zoo system from one place.
          </p>
        </div>

        <div style={styles.grid}>
          <div style={styles.card}><h3>Animals</h3><p style={styles.number}>{counts.totalAnimals}</p></div>
          <div style={styles.card}><h3>Enclosures</h3><p style={styles.number}>{counts.totalEnclosures}</p></div>
          <div style={styles.card}><h3>Staff</h3><p style={styles.number}>{counts.totalStaff}</p></div>
          <div style={styles.card}><h3>Feeding</h3><p style={styles.number}>{counts.totalFeedingSchedules}</p></div>
          <div style={styles.card}><h3>Medical</h3><p style={styles.number}>{counts.totalMedicalRecords}</p></div>
          <div style={styles.card}><h3>Users</h3><p style={styles.number}>{counts.totalUsers}</p></div>
        </div>

        <div style={styles.actions}>
          <button style={styles.button} onClick={() => navigate("/animals")}>Manage Animals</button>
          <button style={styles.button} onClick={() => navigate("/enclosures")}>Manage Enclosures</button>
          <button style={styles.button} onClick={() => navigate("/staff")}>Manage Staff</button>
          <button style={styles.button} onClick={() => navigate("/feeding-schedules")}>Manage Feeding</button>
          <button style={styles.button} onClick={() => navigate("/medical-records")}>Manage Medical</button>
          <button style={styles.button} onClick={() => navigate("/users")}>Manage Users</button>
        </div>
      </div>
    </div>
  );
}

const styles = {
  page: {
    minHeight: "100vh",
    background: "linear-gradient(135deg, #f8fafc, #e0f2fe)",
    fontFamily: "Arial, sans-serif",
  },
  container: {
    width: "90%",
    maxWidth: "1200px",
    margin: "0 auto",
    padding: "30px 0 50px",
  },
  headerCard: {
    background: "linear-gradient(135deg, #0f172a, #1d4ed8)",
    color: "#fff",
    borderRadius: "22px",
    padding: "35px",
    boxShadow: "0 10px 28px rgba(0,0,0,0.15)",
    marginBottom: "30px",
  },
  title: {
    margin: 0,
    fontSize: "2.4rem",
  },
  subtitle: {
    marginTop: "12px",
    color: "rgba(255,255,255,0.9)",
  },
  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))",
    gap: "20px",
  },
  card: {
    background: "#fff",
    borderRadius: "16px",
    padding: "24px",
    textAlign: "center",
    boxShadow: "0 8px 18px rgba(0,0,0,0.08)",
  },
  number: {
    fontSize: "2rem",
    fontWeight: "bold",
    color: "#2563eb",
    marginTop: "10px",
  },
  actions: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))",
    gap: "16px",
    marginTop: "30px",
  },
  button: {
    background: "#111827",
    color: "#fff",
    border: "none",
    padding: "14px 18px",
    borderRadius: "10px",
    fontWeight: "bold",
    cursor: "pointer",
  },
};

export default Admin;
